import{_ as a,o as n,c as l,a2 as p}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Binary Releases","description":"Automate the creation and publication of prebuilt binary releases on GitHub with checksums, signatures, and platform-specific archives.","frontmatter":{"title":"Binary Releases","description":"Automate the creation and publication of prebuilt binary releases on GitHub with checksums, signatures, and platform-specific archives."},"headers":[],"relativePath":"learn/linear/17-packaging-and-distribution/06-binary-releases.md","filePath":"learn/linear/17-packaging-and-distribution/06-binary-releases.md"}'),o={name:"learn/linear/17-packaging-and-distribution/06-binary-releases.md"};function e(t,s,c,r,i,y){return n(),l("div",null,[...s[0]||(s[0]=[p(`<h1 id="binary-releases" tabindex="-1">Binary Releases <a class="header-anchor" href="#binary-releases" aria-label="Permalink to &quot;Binary Releases&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to set up GitHub Actions workflows that build, package, and publish binary releases for all platforms on git tag push</li><li>Techniques for creating platform-appropriate archives (tar.gz for Unix, zip for Windows) with checksums and optional GPG signatures</li><li>How to write install scripts (curl-pipe-bash style) that detect the user&#39;s platform and download the correct binary automatically</li></ul></blockquote><p>Prebuilt binary releases are the primary distribution mechanism for production CLI tools. Users do not want to install a Rust toolchain, wait for compilation, or debug build failures. They want to download a binary and run it. GitHub Releases provide the infrastructure for this: host platform-specific archives, attach checksums for verification, and let users download from a stable URL. This subchapter covers the complete pipeline from git tag to published release.</p><h2 id="the-release-pipeline-overview" tabindex="-1">The Release Pipeline Overview <a class="header-anchor" href="#the-release-pipeline-overview" aria-label="Permalink to &quot;The Release Pipeline Overview&quot;">​</a></h2><p>The typical release pipeline for a Rust CLI tool follows these steps:</p><ol><li>You push a git tag (<code>v0.5.2</code>)</li><li>CI triggers a matrix build across all target platforms</li><li>Each build produces an optimized binary (using the release profile from subchapter 1)</li><li>Binaries are packaged into platform-appropriate archives with completions and docs</li><li>SHA256 checksums are computed for every archive</li><li>A GitHub Release is created with all archives and checksums attached</li><li>Downstream distribution (Homebrew tap, install scripts) is updated automatically</li></ol><p>Let&#39;s build this pipeline step by step.</p><h2 id="packaging-binaries" tabindex="-1">Packaging Binaries <a class="header-anchor" href="#packaging-binaries" aria-label="Permalink to &quot;Packaging Binaries&quot;">​</a></h2><p>Before uploading to GitHub Releases, package each binary into an archive with supporting files. The convention is <code>tar.gz</code> for Unix and <code>zip</code> for Windows:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F5C2E7;font-style:italic;">#!/bin/bash</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">set</span><span style="color:#A6E3A1;"> -euo</span><span style="color:#A6E3A1;"> pipefail</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">BINARY_NAME</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">VERSION</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#EBA0AC;font-style:italic;">\${1</span><span style="color:#94E2D5;">:?</span><span style="color:#CDD6F4;">Usage</span><span style="color:#94E2D5;">:</span><span style="color:#CDD6F4;"> package</span><span style="color:#A6E3A1;">.</span><span style="color:#CDD6F4;">sh</span><span style="color:#A6E3A1;"> &lt;</span><span style="color:#CDD6F4;">version</span><span style="color:#A6E3A1;">&gt;</span><span style="color:#EBA0AC;font-style:italic;">}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">TARGET</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#EBA0AC;font-style:italic;">\${2</span><span style="color:#94E2D5;">:?</span><span style="color:#CDD6F4;">Usage</span><span style="color:#94E2D5;">:</span><span style="color:#CDD6F4;"> package</span><span style="color:#A6E3A1;">.</span><span style="color:#CDD6F4;">sh</span><span style="color:#A6E3A1;"> &lt;</span><span style="color:#CDD6F4;">version</span><span style="color:#A6E3A1;">&gt; &lt;</span><span style="color:#CDD6F4;">target</span><span style="color:#A6E3A1;">&gt;</span><span style="color:#EBA0AC;font-style:italic;">}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">BINARY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;target/</span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">/release/</span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#9399B2;"> [[</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#94E2D5;"> ==</span><span style="color:#94E2D5;"> *</span><span style="color:#A6E3A1;">&quot;windows&quot;</span><span style="color:#94E2D5;">*</span><span style="color:#9399B2;"> ]];</span><span style="color:#CBA6F7;"> then</span></span>
<span class="line"><span style="color:#CDD6F4;">    BINARY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#CDD6F4;">\${BINARY}</span><span style="color:#A6E3A1;">.exe&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">ARCHIVE_DIR</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;">-</span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#A6E3A1;">-</span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">mkdir</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Copy binary</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cp</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${BINARY}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">/&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Copy supporting files</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cp</span><span style="color:#A6E3A1;"> README.md</span><span style="color:#A6E3A1;"> LICENSE</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">/&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Copy shell completions (if they exist)</span></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#9399B2;"> [</span><span style="color:#94E2D5;"> -d</span><span style="color:#A6E3A1;"> &quot;completions&quot;</span><span style="color:#9399B2;"> ];</span><span style="color:#CBA6F7;"> then</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    cp</span><span style="color:#A6E3A1;"> -r</span><span style="color:#A6E3A1;"> completions</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">/&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Copy man page (if it exists)</span></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#9399B2;"> [</span><span style="color:#94E2D5;"> -d</span><span style="color:#A6E3A1;"> &quot;man&quot;</span><span style="color:#9399B2;"> ];</span><span style="color:#CBA6F7;"> then</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    cp</span><span style="color:#A6E3A1;"> -r</span><span style="color:#A6E3A1;"> man</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">/&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Create archive</span></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#9399B2;"> [[</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#94E2D5;"> ==</span><span style="color:#94E2D5;"> *</span><span style="color:#A6E3A1;">&quot;windows&quot;</span><span style="color:#94E2D5;">*</span><span style="color:#9399B2;"> ]];</span><span style="color:#CBA6F7;"> then</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    zip</span><span style="color:#A6E3A1;"> -r</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">.zip&quot;</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;Created </span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">.zip&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">else</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    tar</span><span style="color:#A6E3A1;"> czf</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">.tar.gz&quot;</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;Created </span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Clean up</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rm</span><span style="color:#A6E3A1;"> -rf</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCHIVE_DIR}</span><span style="color:#A6E3A1;">&quot;</span></span></code></pre></div><p>The archive contents look like:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>my-agent-0.5.2-x86_64-unknown-linux-musl/</span></span>
<span class="line"><span>  my-agent                    # The binary</span></span>
<span class="line"><span>  README.md                   # Project readme</span></span>
<span class="line"><span>  LICENSE                     # License file</span></span>
<span class="line"><span>  completions/</span></span>
<span class="line"><span>    my-agent.bash             # Bash completions</span></span>
<span class="line"><span>    _my-agent                 # Zsh completions</span></span>
<span class="line"><span>    my-agent.fish             # Fish completions</span></span>
<span class="line"><span>  man/</span></span>
<span class="line"><span>    my-agent.1                # Man page</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python distribution archives (wheels and sdists) have a strict format defined by PEP standards and include metadata files, dependency declarations, and platform tags. Rust release archives are simpler: just the binary and whatever supporting files you choose to include. There is no runtime dependency resolution, no package metadata format, and no compatibility tag negotiation. The binary runs or it does not.</p></div><h2 id="sha256-checksums" tabindex="-1">SHA256 Checksums <a class="header-anchor" href="#sha256-checksums" aria-label="Permalink to &quot;SHA256 Checksums&quot;">​</a></h2><p>Every release should include a checksum file that users can verify against. This catches corrupted downloads and provides a basic tamper detection mechanism:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Generate checksums for all archives</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">shasum</span><span style="color:#A6E3A1;"> -a</span><span style="color:#FAB387;"> 256</span><span style="color:#A6E3A1;"> my-agent-0.5.2-</span><span style="color:#CDD6F4;">*</span><span style="color:#A6E3A1;">.tar.gz</span><span style="color:#A6E3A1;"> my-agent-0.5.2-</span><span style="color:#CDD6F4;">*</span><span style="color:#A6E3A1;">.zip</span><span style="color:#94E2D5;"> &gt;</span><span style="color:#A6E3A1;"> SHA256SUMS.txt</span></span></code></pre></div><p>The resulting file looks like:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>a1b2c3d4...  my-agent-0.5.2-aarch64-apple-darwin.tar.gz</span></span>
<span class="line"><span>e5f6a7b8...  my-agent-0.5.2-x86_64-apple-darwin.tar.gz</span></span>
<span class="line"><span>c9d0e1f2...  my-agent-0.5.2-x86_64-unknown-linux-musl.tar.gz</span></span>
<span class="line"><span>a3b4c5d6...  my-agent-0.5.2-aarch64-unknown-linux-musl.tar.gz</span></span>
<span class="line"><span>e7f8a9b0...  my-agent-0.5.2-x86_64-pc-windows-msvc.zip</span></span></code></pre></div><p>Users verify a download with:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Download the binary and checksums</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> -LO</span><span style="color:#A6E3A1;"> https://github.com/yourname/my-agent/releases/download/v0.5.2/my-agent-0.5.2-x86_64-unknown-linux-musl.tar.gz</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> -LO</span><span style="color:#A6E3A1;"> https://github.com/yourname/my-agent/releases/download/v0.5.2/SHA256SUMS.txt</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Verify</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">shasum</span><span style="color:#A6E3A1;"> -a</span><span style="color:#FAB387;"> 256</span><span style="color:#A6E3A1;"> -c</span><span style="color:#A6E3A1;"> SHA256SUMS.txt</span><span style="color:#A6E3A1;"> --ignore-missing</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># my-agent-0.5.2-x86_64-unknown-linux-musl.tar.gz: OK</span></span></code></pre></div><h2 id="the-complete-github-actions-workflow" tabindex="-1">The Complete GitHub Actions Workflow <a class="header-anchor" href="#the-complete-github-actions-workflow" aria-label="Permalink to &quot;The Complete GitHub Actions Workflow&quot;">​</a></h2><p>Here is a production-grade release workflow that builds, packages, and publishes for all platforms:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Release</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FAB387;">on</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  push</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    tags</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;v*&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">permissions</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  contents</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> write</span><span style="color:#6C7086;font-style:italic;">  # Required to create GitHub Releases</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">env</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  BINARY_NAME</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> my-agent</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">jobs</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  build</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    strategy</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">      fail-fast</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> false</span></span>
<span class="line"><span style="color:#89B4FA;">      matrix</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">        include</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> aarch64-apple-darwin</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> macos-latest</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> x86_64-apple-darwin</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> macos-latest</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> aarch64-unknown-linux-musl</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#89B4FA;">            use_cross</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#9399B2;">          -</span><span style="color:#89B4FA;"> target</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> x86_64-pc-windows-msvc</span></span>
<span class="line"><span style="color:#89B4FA;">            os</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> windows-latest</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">    runs-on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ matrix.os }}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">    steps</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/checkout@v4</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> dtolnay/rust-toolchain@stable</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          targets</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ matrix.target }}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Install cross</span></span>
<span class="line"><span style="color:#89B4FA;">        if</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> matrix.use_cross</span></span>
<span class="line"><span style="color:#89B4FA;">        run</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> cargo install cross --git https://github.com/cross-rs/cross</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Install musl-tools</span></span>
<span class="line"><span style="color:#89B4FA;">        if</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> matrix.target == &#39;x86_64-unknown-linux-musl&#39;</span></span>
<span class="line"><span style="color:#89B4FA;">        run</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> sudo apt install -y musl-tools</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Build</span></span>
<span class="line"><span style="color:#89B4FA;">        shell</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> bash</span></span>
<span class="line"><span style="color:#89B4FA;">        run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">          if [ &quot;\${{ matrix.use_cross }}&quot; = &quot;true&quot; ]; then</span></span>
<span class="line"><span style="color:#A6E3A1;">            cross build --release --target \${{ matrix.target }}</span></span>
<span class="line"><span style="color:#A6E3A1;">          else</span></span>
<span class="line"><span style="color:#A6E3A1;">            cargo build --release --target \${{ matrix.target }}</span></span>
<span class="line"><span style="color:#A6E3A1;">          fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Package</span></span>
<span class="line"><span style="color:#89B4FA;">        shell</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> bash</span></span>
<span class="line"><span style="color:#89B4FA;">        run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">          VERSION=&quot;\${GITHUB_REF_NAME#v}&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          TARGET=&quot;\${{ matrix.target }}&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          ARCHIVE_DIR=&quot;\${BINARY_NAME}-\${VERSION}-\${TARGET}&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          mkdir -p &quot;\${ARCHIVE_DIR}&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">          if [[ &quot;\${TARGET}&quot; == *&quot;windows&quot;* ]]; then</span></span>
<span class="line"><span style="color:#A6E3A1;">            cp &quot;target/\${TARGET}/release/\${BINARY_NAME}.exe&quot; &quot;\${ARCHIVE_DIR}/&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          else</span></span>
<span class="line"><span style="color:#A6E3A1;">            cp &quot;target/\${TARGET}/release/\${BINARY_NAME}&quot; &quot;\${ARCHIVE_DIR}/&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">          cp README.md LICENSE &quot;\${ARCHIVE_DIR}/&quot; 2&gt;/dev/null || true</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">          if [[ &quot;\${TARGET}&quot; == *&quot;windows&quot;* ]]; then</span></span>
<span class="line"><span style="color:#A6E3A1;">            7z a &quot;\${ARCHIVE_DIR}.zip&quot; &quot;\${ARCHIVE_DIR}&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          else</span></span>
<span class="line"><span style="color:#A6E3A1;">            tar czf &quot;\${ARCHIVE_DIR}.tar.gz&quot; &quot;\${ARCHIVE_DIR}&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">          fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Upload artifact</span></span>
<span class="line"><span style="color:#89B4FA;">        uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/upload-artifact@v4</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> archive-\${{ matrix.target }}</span></span>
<span class="line"><span style="color:#89B4FA;">          path</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ env.BINARY_NAME }}-*-\${{ matrix.target }}.*</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">  release</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    needs</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> build</span></span>
<span class="line"><span style="color:#89B4FA;">    runs-on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#89B4FA;">    steps</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Download all artifacts</span></span>
<span class="line"><span style="color:#89B4FA;">        uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/download-artifact@v4</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          path</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> artifacts</span></span>
<span class="line"><span style="color:#89B4FA;">          merge-multiple</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Generate checksums</span></span>
<span class="line"><span style="color:#89B4FA;">        run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">          cd artifacts</span></span>
<span class="line"><span style="color:#A6E3A1;">          shasum -a 256 *.tar.gz *.zip 2&gt;/dev/null &gt; SHA256SUMS.txt</span></span>
<span class="line"><span style="color:#A6E3A1;">          cat SHA256SUMS.txt</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Create GitHub Release</span></span>
<span class="line"><span style="color:#89B4FA;">        uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> softprops/action-gh-release@v2</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          files</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">            artifacts/*.tar.gz</span></span>
<span class="line"><span style="color:#A6E3A1;">            artifacts/*.zip</span></span>
<span class="line"><span style="color:#A6E3A1;">            artifacts/SHA256SUMS.txt</span></span>
<span class="line"><span style="color:#89B4FA;">          generate_release_notes</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">          draft</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> false</span></span>
<span class="line"><span style="color:#89B4FA;">          prerelease</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ contains(github.ref_name, &#39;-rc&#39;) || contains(github.ref_name, &#39;-beta&#39;) }}</span></span></code></pre></div><p>Key design decisions in this workflow:</p><ul><li><strong><code>fail-fast: false</code></strong> -- If one platform fails, the others continue building. You can fix the failing platform and re-run just that job.</li><li><strong><code>permissions: contents: write</code></strong> -- Required to create releases. Use the minimum permissions necessary.</li><li><strong><code>generate_release_notes: true</code></strong> -- GitHub automatically generates release notes from merged PRs since the last release.</li><li><strong>Prerelease detection</strong> -- Tags containing <code>-rc</code> or <code>-beta</code> are automatically marked as pre-releases.</li></ul><h2 id="using-cargo-dist" tabindex="-1">Using <code>cargo-dist</code> <a class="header-anchor" href="#using-cargo-dist" aria-label="Permalink to &quot;Using \`cargo-dist\`&quot;">​</a></h2><p>For projects that want a turnkey solution, <a href="https://opensource.axo.dev/cargo-dist/" target="_blank" rel="noreferrer"><code>cargo-dist</code></a> generates the entire release pipeline:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install cargo-dist</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> cargo-dist</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Initialize -- interactive setup</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> dist</span><span style="color:#A6E3A1;"> init</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Generate CI configuration</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> dist</span><span style="color:#A6E3A1;"> generate</span></span></code></pre></div><p><code>cargo-dist</code> creates a <code>.github/workflows/release.yml</code> that handles building, packaging, checksum generation, and GitHub Release creation. It also generates install scripts and Homebrew formulas. It is opinionated but saves significant time if its defaults match your needs.</p><h2 id="install-scripts" tabindex="-1">Install Scripts <a class="header-anchor" href="#install-scripts" aria-label="Permalink to &quot;Install Scripts&quot;">​</a></h2><p>A &quot;curl pipe bash&quot; install script gives users a one-liner to install your tool. Create an <code>install.sh</code> that detects the platform and downloads the right binary:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F5C2E7;font-style:italic;">#!/bin/bash</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">set</span><span style="color:#A6E3A1;"> -euo</span><span style="color:#A6E3A1;"> pipefail</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">REPO</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;yourname/my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">BINARY_NAME</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">INSTALL_DIR</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#CDD6F4;">\${HOME}</span><span style="color:#A6E3A1;">/.local/bin&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Detect platform</span></span>
<span class="line"><span style="color:#CDD6F4;">OS</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">$(</span><span style="color:#89B4FA;font-style:italic;">uname</span><span style="color:#A6E3A1;"> -s</span><span style="color:#9399B2;">)</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">ARCH</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">$(</span><span style="color:#89B4FA;font-style:italic;">uname</span><span style="color:#A6E3A1;"> -m</span><span style="color:#9399B2;">)</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">case</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${OS}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#CBA6F7;"> in</span></span>
<span class="line"><span style="color:#A6E3A1;">    Linux</span><span style="color:#94E2D5;">)</span><span style="color:#CDD6F4;">  OS_TAG</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;unknown-linux-musl&quot;</span><span style="color:#9399B2;"> ;;</span></span>
<span class="line"><span style="color:#A6E3A1;">    Darwin</span><span style="color:#94E2D5;">)</span><span style="color:#CDD6F4;"> OS_TAG</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;apple-darwin&quot;</span><span style="color:#9399B2;"> ;;</span></span>
<span class="line"><span style="color:#94E2D5;">    *)</span><span style="color:#F38BA8;font-style:italic;">      echo</span><span style="color:#A6E3A1;"> &quot;Unsupported OS: </span><span style="color:#CDD6F4;">\${OS}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">;</span><span style="color:#F38BA8;font-style:italic;"> exit</span><span style="color:#FAB387;"> 1</span><span style="color:#9399B2;"> ;;</span></span>
<span class="line"><span style="color:#CBA6F7;">esac</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">case</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${ARCH}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#CBA6F7;"> in</span></span>
<span class="line"><span style="color:#A6E3A1;">    x86_64</span><span style="color:#9399B2;">|</span><span style="color:#A6E3A1;">amd64</span><span style="color:#94E2D5;">)</span><span style="color:#CDD6F4;">  ARCH_TAG</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;x86_64&quot;</span><span style="color:#9399B2;"> ;;</span></span>
<span class="line"><span style="color:#A6E3A1;">    aarch64</span><span style="color:#9399B2;">|</span><span style="color:#A6E3A1;">arm64</span><span style="color:#94E2D5;">)</span><span style="color:#CDD6F4;"> ARCH_TAG</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;aarch64&quot;</span><span style="color:#9399B2;"> ;;</span></span>
<span class="line"><span style="color:#94E2D5;">    *)</span><span style="color:#F38BA8;font-style:italic;">             echo</span><span style="color:#A6E3A1;"> &quot;Unsupported architecture: </span><span style="color:#CDD6F4;">\${ARCH}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">;</span><span style="color:#F38BA8;font-style:italic;"> exit</span><span style="color:#FAB387;"> 1</span><span style="color:#9399B2;"> ;;</span></span>
<span class="line"><span style="color:#CBA6F7;">esac</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">TARGET</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#CDD6F4;">\${ARCH_TAG}</span><span style="color:#A6E3A1;">-</span><span style="color:#CDD6F4;">\${OS_TAG}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Get latest version</span></span>
<span class="line"><span style="color:#CDD6F4;">VERSION</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">$(</span><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> -s</span><span style="color:#A6E3A1;"> &quot;https://api.github.com/repos/</span><span style="color:#CDD6F4;">\${REPO}</span><span style="color:#A6E3A1;">/releases/latest&quot;</span><span style="color:#94E2D5;"> |</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    grep</span><span style="color:#A6E3A1;"> &#39;&quot;tag_name&quot;&#39;</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> sed</span><span style="color:#A6E3A1;"> -E</span><span style="color:#A6E3A1;"> &#39;s/.*&quot;v([^&quot;]+)&quot;.*/\\1/&#39;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#A6E3A1;"> &quot;Installing </span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;"> v</span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#A6E3A1;"> for </span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">...&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Download and extract</span></span>
<span class="line"><span style="color:#CDD6F4;">ARCHIVE</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;">-</span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#A6E3A1;">-</span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">URL</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;https://github.com/</span><span style="color:#CDD6F4;">\${REPO}</span><span style="color:#A6E3A1;">/releases/download/v</span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#A6E3A1;">/</span><span style="color:#CDD6F4;">\${ARCHIVE}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">TMPDIR</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">$(</span><span style="color:#89B4FA;font-style:italic;">mktemp</span><span style="color:#A6E3A1;"> -d</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">trap</span><span style="color:#A6E3A1;"> &quot;rm -rf </span><span style="color:#CDD6F4;">\${TMPDIR}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;"> EXIT</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> -sL</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${URL}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;"> -o</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${TMPDIR}</span><span style="color:#A6E3A1;">/</span><span style="color:#CDD6F4;">\${ARCHIVE}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Verify checksum</span></span>
<span class="line"><span style="color:#CDD6F4;">CHECKSUMS_URL</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;https://github.com/</span><span style="color:#CDD6F4;">\${REPO}</span><span style="color:#A6E3A1;">/releases/download/v</span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#A6E3A1;">/SHA256SUMS.txt&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> -sL</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${CHECKSUMS_URL}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;"> -o</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${TMPDIR}</span><span style="color:#A6E3A1;">/SHA256SUMS.txt&quot;</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">cd</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${TMPDIR}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;"> &amp;&amp;</span><span style="color:#89B4FA;font-style:italic;"> shasum</span><span style="color:#A6E3A1;"> -a</span><span style="color:#FAB387;"> 256</span><span style="color:#A6E3A1;"> -c</span><span style="color:#A6E3A1;"> SHA256SUMS.txt</span><span style="color:#A6E3A1;"> --ignore-missing</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Extract and install</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">tar</span><span style="color:#A6E3A1;"> xzf</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${TMPDIR}</span><span style="color:#A6E3A1;">/</span><span style="color:#CDD6F4;">\${ARCHIVE}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;"> -C</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${TMPDIR}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">mkdir</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${INSTALL_DIR}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cp</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${TMPDIR}</span><span style="color:#A6E3A1;">/</span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;">-</span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#A6E3A1;">-</span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">/</span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${INSTALL_DIR}</span><span style="color:#A6E3A1;">/&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">chmod</span><span style="color:#A6E3A1;"> +x</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${INSTALL_DIR}</span><span style="color:#A6E3A1;">/</span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#A6E3A1;"> &quot;Installed </span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;"> to </span><span style="color:#CDD6F4;">\${INSTALL_DIR}</span><span style="color:#A6E3A1;">/</span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check if install dir is in PATH</span></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#9399B2;"> [[</span><span style="color:#A6E3A1;"> &quot;:</span><span style="color:#CDD6F4;">\${PATH}</span><span style="color:#A6E3A1;">:&quot;</span><span style="color:#94E2D5;"> !=</span><span style="color:#94E2D5;"> *</span><span style="color:#A6E3A1;">&quot;:</span><span style="color:#CDD6F4;">\${INSTALL_DIR}</span><span style="color:#A6E3A1;">:&quot;</span><span style="color:#94E2D5;">*</span><span style="color:#9399B2;"> ]];</span><span style="color:#CBA6F7;"> then</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;Add </span><span style="color:#CDD6F4;">\${INSTALL_DIR}</span><span style="color:#A6E3A1;"> to your PATH:&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;  export PATH=</span><span style="color:#F5C2E7;">\\&quot;\\$</span><span style="color:#A6E3A1;">{HOME}/.local/bin:</span><span style="color:#F5C2E7;">\\$</span><span style="color:#A6E3A1;">{PATH}</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">fi</span></span></code></pre></div><p>Users install with:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> -sSf</span><span style="color:#A6E3A1;"> https://raw.githubusercontent.com/yourname/my-agent/main/install.sh</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> bash</span></span></code></pre></div><p>Host the install script in your repository so it is always up to date. The script automatically fetches the latest release, verifies the checksum, and installs to <code>~/.local/bin</code>.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>The &quot;curl pipe bash&quot; pattern is controversial in the security community because it runs arbitrary code from the internet. Production tools mitigate this by verifying checksums, using HTTPS exclusively, and hosting the script on a domain they control. Many Rust CLI tools (rustup itself uses this pattern) accept the tradeoff because the alternative -- asking users to manually download, extract, and move binaries -- has much lower adoption.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Package binaries into <code>tar.gz</code> (Unix) or <code>zip</code> (Windows) archives containing the binary, shell completions, man pages, README, and LICENSE.</li><li>Always generate and publish SHA256 checksums alongside your release archives so users can verify download integrity.</li><li>Use a GitHub Actions matrix build to compile for all platforms in parallel, then aggregate artifacts into a single release.</li><li>Consider <code>cargo-dist</code> for a turnkey release pipeline that generates CI workflows, install scripts, and Homebrew formulas automatically.</li><li>Provide a platform-detecting install script for users who want a one-command installation without a package manager.</li></ul>`,38)])])}const E=a(o,[["render",e]]);export{u as __pageData,E as default};
